```java
import java.security.MessageDigest;
import java.security.NoSuchAlgorithmException;
import java.nio.charset.StandardCharsets;

public class Main {
    public static void main(String[] args) throws NoSuchAlgorithmException {
        String projectPath = "/path/to/your/project";
        String projectHash = calculateHash(projectPath);
        System.out.println("Project Hash: " + projectHash);
    }

    public static String calculateHash(String path) throws NoSuchAlgorithmException {
        MessageDigest md = MessageDigest.getInstance("SHA-256");
        File file = new File(path);
        byte[] hashBytes = md.digest(file.toString().getBytes(StandardCharsets.UTF_8));
        return bytesToHex(hashBytes);
    }

    public static String bytesToHex(byte[] bytes) {
        StringBuilder sb = new StringBuilder();
        for (byte b : bytes) {
            sb.append(String.format("%02x", b));
        }
        return sb.toString();
    }
}
```

